import{_ as a,o as t,c as s,ae as r}from"./chunks/framework.CiBL6oPQ.js";const u=JSON.parse('{"title":"MVC Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/mvc.md","filePath":"architecture/mvc.md"}'),n={name:"architecture/mvc.md"};function o(i,e,l,c,d,p){return t(),s("div",null,[...e[0]||(e[0]=[r(`<h1 id="mvc-architecture" tabindex="-1">MVC Architecture <a class="header-anchor" href="#mvc-architecture" aria-label="Permalink to &quot;MVC Architecture&quot;">​</a></h1><p>The <strong>Model-View-Controller (MVC)</strong> architecture is the default choice for the majority of web applications and APIs. It provides a clean separation between data, business logic, and presentation.</p><h2 id="directory-structure" tabindex="-1">Directory Structure <a class="header-anchor" href="#directory-structure" aria-label="Permalink to &quot;Directory Structure&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/</span></span>
<span class="line"><span>├── config/         # Configuration for DB, Redis, etc.</span></span>
<span class="line"><span>├── controllers/    # Request handlers (logic goes here)</span></span>
<span class="line"><span>├── models/         # Data schemas and models</span></span>
<span class="line"><span>├── routes/         # API endpoint definitions</span></span>
<span class="line"><span>├── utils/          # Middleware and utilities</span></span>
<span class="line"><span>└── index.ts        # App entry point</span></span></code></pre></div><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><ol><li><strong>Routes</strong>: Capture incoming requests and delegate them to the appropriate <strong>Controller</strong>.</li><li><strong>Controllers</strong>: Contain the main business logic. They interact with <strong>Models</strong> to fetch or save data and send responses.</li><li><strong>Models</strong>: Represent the data structure (Mongoose, Sequelize, or TypeORM).</li><li><strong>Error Handling</strong>: Controllers pass errors to the <code>next(error)</code> function, which is handled centrally by a global error middleware.</li></ol><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><ul><li>Standard REST APIs.</li><li>Small to medium-sized microservices.</li><li>Server-side rendered (SSR) web applications (using EJS or Pug).</li></ul>`,8)])])}const g=a(n,[["render",o]]);export{u as __pageData,g as default};
